"use client";

import { useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { authService } from "@/lib/api/auth";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { useToast } from "@/hooks/use-toast"; // Assuming this hook exists, if not I'll use simple alert or remove

export default function LoginPage() {
  const router = useRouter();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError("");

    try {
      await authService.login({ email, password });

      // Redirect based on role (handled by authService or manual check)
      // authService.getUser() might be needed to confirm role if not returned in login
      const user = JSON.parse(localStorage.getItem("user") || "{}");

      if (user.role === 'admin') {
        router.push("/admin/dashboard");
      } else if (user.role === 'therapist') {
        router.push("/therapist/dashboard");
      } else {
        router.push("/dashboard"); // Default for patient
      }

    } catch (err: unknown) {
      console.error(err);
      setError(err.response?.data?.message || "Invalid email or password");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Card className="w-full">
      <CardHeader>
        <CardTitle className="text-2xl text-center">Welcome back</CardTitle>
        <CardDescription className="text-center">
          Enter your email to sign in to your account
        </CardDescription>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleLogin} className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="email">Email</Label>
            <Input
              id="email"
              type="email"
              placeholder="m@example.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="password">Password</Label>
            <Input
              id="password"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>
          {error && (
            <div className="text-sm text-red-500 font-medium">
              {error}
            </div>
          )}
          <Button type="submit" className="w-full" disabled={isLoading}>
            {isLoading ? "Signing in..." : "Sign In"}
          </Button>
        </form>
      </CardContent>
      <CardFooter className="flex justify-center">
        <p className="text-sm text-gray-500">
          Don&apos;t have an account?{" "}
          <Link href="/register" className="text-blue-600 hover:underline">
            Sign up
          </Link>
        </p>
      </CardFooter>
    </Card>
  );
}

"use client";

import { useEffect, useState } from "react";
import { pmService } from "@/lib/api/pm";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Plus } from "lucide-react";
import { BacklogTable } from "@/components/pm-dashboard/backlog-table";
import { FeatureForm } from "@/components/pm-dashboard/feature-form";
import { toast } from "@/components/ui/use-toast";
import { Loader2 } from "lucide-react";

export default function PMBacklogPage() {
  const [features, setFeatures] = useState<unknown[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isCreateOpen, setIsCreateOpen] = useState(false);
  const [isCreating, setIsCreating] = useState(false);

  const fetchFeatures = async () => {
    setIsLoading(true);
    try {
      const data = await pmService.getFeatures();
      setFeatures(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error("Failed to fetch features", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchFeatures();
  }, []);

  const handleCreate = async (data: unknown) => {
    setIsCreating(true);
    try {
      await pmService.createFeature(data);
      toast({ title: "Success", description: "Feature created successfully" });
      fetchFeatures();
      setIsCreateOpen(false);
    } catch (_error) {
      toast({ title: "Error", description: "Failed to create feature", variant: "destructive" });
    } finally {
      setIsCreating(false);
    }
  };

  if (isLoading && features.length === 0) {
    return (
      <div className="flex h-96 items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="flex-1 space-y-4 p-8 pt-6">
      <div className="flex items-center justify-between space-y-2">
        <h2 className="text-3xl font-bold tracking-tight">Product Backlog</h2>
        <Dialog open={isCreateOpen} onOpenChange={setIsCreateOpen}>
          <DialogTrigger asChild>
            <Button>
              <Plus className="mr-2 h-4 w-4" /> Add Feature
            </Button>
          </DialogTrigger>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Create New Feature</DialogTitle>
            </DialogHeader>
            <FeatureForm onSubmit={handleCreate} isLoading={isCreating} />
          </DialogContent>
        </Dialog>
      </div>

      <BacklogTable data={features} onUpdate={fetchFeatures} />
    </div>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Plus, Pencil, Trash2, Check, X, Download } from "lucide-react";
import { useEffect, useState } from "react";
import { pmService } from "@/lib/api/pm";
import { SubscriptionPlan } from "@/lib/api/settings";
import { useToast } from "@/hooks/use-toast";
import { PlanForm } from "@/components/product-manager/plans/plan-form";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";

export default function PlansPage() {
  const [plans, setPlans] = useState<SubscriptionPlan[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [selectedPlan, setSelectedPlan] = useState<SubscriptionPlan | null>(null);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const { toast } = useToast();

  const fetchPlans = async () => {
    setIsLoading(true);
    try {
      const data = await pmService.getPlans();
      // Ensure we handle both direct array and wrapped response
      setPlans(Array.isArray(data) ? data : data.data || []);
    } catch (error) {
      console.error("Failed to fetch plans", error);
      toast({
        title: "Error",
        description: "Failed to load subscription plans",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchPlans();
  }, []);

  const handleCreate = () => {
    setSelectedPlan(null);
    setIsDialogOpen(true);
  };

  const handleEdit = (plan: SubscriptionPlan) => {
    setSelectedPlan(plan);
    setIsDialogOpen(true);
  };

  const handleDelete = async () => {
    if (!deleteId) return;
    try {
      await pmService.deletePlan(deleteId);
      toast({ title: "Success", description: "Plan deleted successfully" });
      fetchPlans();
    } catch (error) {
      console.error(error);
      toast({ title: "Error", description: "Failed to delete plan", variant: "destructive" });
    } finally {
      setDeleteId(null);
    }
  };

  const handleSubmit = async (data: unknown) => {
    try {
      if (selectedPlan) {
        await pmService.updatePlan(selectedPlan.id, data);
        toast({ title: "Success", description: "Plan updated successfully" });
      } else {
        await pmService.createPlan(data);
        toast({ title: "Success", description: "Plan created successfully" });
      }
      fetchPlans();
    } catch (error) {
      console.error(error);
      toast({ title: "Error", description: "Operation failed", variant: "destructive" });
      throw error;
    }
  };

  const handleExport = () => {
    const csvContent = "data:text/csv;charset=utf-8," 
      + "Name,Slug,Price,Currency,Interval,Max Sessions,Active\n"
      + plans.map(p => `"${p.name}","${p.slug}",${p.price},"${p.currency}","${p.billing_interval}",${p.max_sessions},${p.is_active}`).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "plans_export.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="flex flex-col gap-6 p-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Subscription Plans</h1>
          <p className="text-muted-foreground">
            Manage subscription plans, pricing, and features.
          </p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" onClick={handleExport}>
            <Download className="mr-2 h-4 w-4" /> Export CSV
          </Button>
          <Button onClick={handleCreate}>
            <Plus className="mr-2 h-4 w-4" />
            Create Plan
          </Button>
        </div>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>All Plans</CardTitle>
          <CardDescription>
            A list of all available subscription plans.
          </CardDescription>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="flex justify-center p-4">Loading plans...</div>
          ) : plans.length === 0 ? (
            <div className="text-center p-4 text-muted-foreground">No plans found. Create one to get started.</div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Name</TableHead>
                  <TableHead>Price</TableHead>
                  <TableHead>Interval</TableHead>
                  <TableHead>Max Sessions</TableHead>
                  <TableHead>Active</TableHead>
                  <TableHead className="text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {plans.map((plan) => (
                  <TableRow key={plan.id}>
                    <TableCell className="font-medium">
                      <div>{plan.name}</div>
                      <div className="text-xs text-muted-foreground">{plan.slug}</div>
                    </TableCell>
                    <TableCell>
                      {plan.currency} {plan.price}
                    </TableCell>
                    <TableCell className="capitalize">
                      {plan.billing_interval.replace('_', ' ')}
                    </TableCell>
                    <TableCell>
                      {plan.max_sessions === 0 ? "Unlimited" : plan.max_sessions}
                    </TableCell>
                    <TableCell>
                      {plan.is_active ? (
                        <Check className="h-4 w-4 text-green-500" />
                      ) : (
                        <X className="h-4 w-4 text-red-500" />
                      )}
                    </TableCell>
                    <TableCell className="text-right">
                      <div className="flex justify-end gap-2">
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => handleEdit(plan)}
                        >
                          <Pencil className="h-4 w-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          className="text-red-500 hover:text-red-600"
                          onClick={() => setDeleteId(plan.id)}
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      <PlanForm
        open={isDialogOpen}
        onOpenChange={setIsDialogOpen}
        plan={selectedPlan}
        onSubmit={handleSubmit}
      />

      <AlertDialog open={!!deleteId} onOpenChange={(open) => !open && setDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Are you absolutely sure?</AlertDialogTitle>
            <AlertDialogDescription>
              This action cannot be undone. This will permanently delete the subscription plan.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} className="bg-red-500 hover:bg-red-600">
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { pmService } from "@/lib/api/pm";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Loader2, Calendar, CheckCircle, Clock, AlertCircle, Plus, Pencil, Download } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { FeatureForm } from "@/components/pm-dashboard/feature-form";
import { toast } from "@/components/ui/use-toast";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

export default function PMRoadmapPage() {
  const [roadmapGroups, setRoadmapGroups] = useState<unknown[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isCreating, setIsCreating] = useState(false);
  const [isCreateOpen, setIsCreateOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<unknown | null>(null);
  const [isEditOpen, setIsEditOpen] = useState(false);

  const fetchRoadmap = async () => {
    try {
      const data = await pmService.getRoadmap();
      // Ensure data is array
      setRoadmapGroups(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error(error);
      toast({ title: "Error", description: "Failed to fetch roadmap", variant: "destructive" });
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchRoadmap();
  }, []);

  const handleCreate = async (data: unknown) => {
    setIsCreating(true);
    try {
      await pmService.createRoadmapItem(data);
      toast({ title: "Success", description: "Roadmap item created successfully" });
      fetchRoadmap();
      setIsCreateOpen(false);
    } catch (_error) {
      toast({ title: "Error", description: "Failed to create item", variant: "destructive" });
    } finally {
      setIsCreating(false);
    }
  };

  const handleEdit = async (data: unknown) => {
    if (!editingItem) return;
    setIsCreating(true);
    try {
      await pmService.updateRoadmapItem(editingItem.id, data);
      toast({ title: "Success", description: "Item updated successfully" });
      fetchRoadmap();
      setIsEditOpen(false);
      setEditingItem(null);
    } catch (_error) {
      toast({ title: "Error", description: "Failed to update item", variant: "destructive" });
    } finally {
      setIsCreating(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this item?")) return;
    try {
      await pmService.deleteRoadmapItem(id);
      toast({ title: "Success", description: "Item deleted successfully" });
      fetchRoadmap();
    } catch (_error) {
      toast({ title: "Error", description: "Failed to delete item", variant: "destructive" });
    }
  };

  const openEditDialog = (item: unknown) => {
    setEditingItem(item);
    setIsEditOpen(true);
  };

  const handleExport = () => {
    let csvContent = "data:text/csv;charset=utf-8,Quarter,Title,Description,Status,Priority,Target Date\n";

    roadmapGroups.forEach(group => {
      group.features.forEach((f: unknown) => {
        csvContent += `"${group.quarter}","${f.title}","${f.description || ''}",${f.status},${f.priority},${f.target_date || ''}\n`;
      });
    });

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "roadmap_export.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  if (isLoading) {
    return (
      <div className="flex h-96 items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'completed': return <CheckCircle className="h-4 w-4 text-green-500" />;
      case 'in_progress': return <Clock className="h-4 w-4 text-blue-500" />;
      default: return <AlertCircle className="h-4 w-4 text-gray-500" />;
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed': return "bg-green-100 text-green-800";
      case 'in_progress': return "bg-blue-100 text-blue-800";
      case 'review': return "bg-purple-100 text-purple-800";
      default: return "bg-gray-100 text-gray-800";
    }
  };

  return (
    <div className="flex-1 space-y-4 p-8 pt-6">
      <div className="flex items-center justify-between space-y-2">
        <h2 className="text-3xl font-bold tracking-tight">Product Roadmap</h2>
        <div className="flex items-center gap-2">
          <Button variant="outline" onClick={handleExport}>
            <Download className="mr-2 h-4 w-4" /> Export CSV
          </Button>
          <Dialog open={isCreateOpen} onOpenChange={setIsCreateOpen}>
            <DialogTrigger asChild>
              <Button>
                <Plus className="mr-2 h-4 w-4" /> Add Item
              </Button>
            </DialogTrigger>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>Add Roadmap Item</DialogTitle>
              </DialogHeader>
              <FeatureForm onSubmit={handleCreate} isLoading={isCreating} />
            </DialogContent>
          </Dialog>
        </div>
      </div>

      <Dialog open={isEditOpen} onOpenChange={setIsEditOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Edit Roadmap Item</DialogTitle>
          </DialogHeader>
          <FeatureForm initialData={editingItem} onSubmit={handleEdit} isLoading={isCreating} />
        </DialogContent>
      </Dialog>

      <div className="space-y-8">
        {roadmapGroups.map((group) => (
          <div key={group.quarter} className="space-y-4">
            <h3 className="text-xl font-semibold border-b pb-2">{group.quarter}</h3>
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
              {group.features.map((item: unknown) => (
                <Card key={item.id} className="relative group">
                  <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button variant="ghost" className="h-8 w-8 p-0">
                          <span className="sr-only">Open menu</span>
                          <Pencil className="h-4 w-4" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuItem onClick={() => openEditDialog(item)}>
                          Edit
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => handleDelete(item.id)} className="text-red-600">
                          Delete
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </div>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">
                      {item.name}
                    </CardTitle>
                    {getStatusIcon(item.status)}
                  </CardHeader>
                  <CardContent>
                    <div className="flex flex-col gap-2 mt-2">
                      <Badge variant="secondary" className={`w-fit ${getStatusColor(item.status)}`}>
                        {item.status.replace('_', ' ')}
                      </Badge>
                      <div className="flex items-center text-xs text-muted-foreground">
                        <Calendar className="mr-1 h-3 w-3" />
                        Due: {item.target_date || 'N/A'}
                      </div>
                      <div className="text-xs font-medium mt-2">
                        Priority: <span className={item.priority === 'high' ? 'text-red-500' : 'text-gray-500'}>{item.priority}</span>
                      </div>
                      <p className="text-xs text-muted-foreground mt-2 line-clamp-2">
                        {item.description}
                      </p>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          </div>
        ))}
        {roadmapGroups.length === 0 && (
          <div className="text-center text-muted-foreground py-10">
            No roadmap items found. Click &quot;Add Item" to start planning.
          </div>
        )}
      </div>
    </div>
  );
}

