import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Slider } from "@/components/ui/slider";
import { useState, useEffect } from "react";
import { Loader2 } from "lucide-react";

export function AiSettings() {
  const { settings, updateSettings, isLoading } = useSettingsStore();
  const [formData, setFormData] = useState(settings?.ai || {});

  useEffect(() => {
    if (settings?.ai) {
      setFormData(settings.ai);
    }
  }, [settings]);

  const handleSave = () => {
    updateSettings("ai", formData);
  };

  if (!settings) return null;

  return (
    <div className="space-y-4">
      <Card>
        <CardHeader>
          <CardTitle>AI Configuration</CardTitle>
          <CardDescription>Manage AI models and API keys.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <Label>OpenAI API Key</Label>
            <Input 
              type="password"
              value={formData.openaiKey || ""} 
              onChange={e => setFormData({...formData, openaiKey: e.target.value})} 
              placeholder="sk-..."
            />
          </div>
          <div className="space-y-2">
            <Label>Anthropic API Key</Label>
            <Input 
              type="password"
              value={formData.anthropicKey || ""} 
