"use client";

import { useSettingsStore } from "@/store/settings-store";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useState } from "react";
import { Plus, Pencil, Trash2 } from "lucide-react";
import { SubscriptionPlan } from "@/lib/api/settings";
import { toast } from "@/components/ui/use-toast";

export function SubscriptionSettings() {
  const { plans, createPlan, updatePlan, deletePlan, isLoading } = useSettingsStore();
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [selectedPlan, setSelectedPlan] = useState<SubscriptionPlan | null>(null);

  const handleEdit = (plan: SubscriptionPlan) => {
    setSelectedPlan(plan);
    setIsDialogOpen(true);
  };

  const handleCreate = () => {
    setSelectedPlan(null);
    setIsDialogOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (confirm("Are you sure you want to delete this plan?")) {
      await deletePlan(id);
    }
  };

  return (
    <Card>
      <CardHeader className="flex flex-row items-center justify-between">
        <div>
          <CardTitle>Subscription Plans</CardTitle>
          <CardDescription>Manage pricing tiers and plan features.</CardDescription>
        </div>
        <Button onClick={handleCreate}>
          <Plus className="mr-2 h-4 w-4" /> Add Plan
        </Button>
      </CardHeader>
      <CardContent>
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Name</TableHead>
              <TableHead>Price</TableHead>
              <TableHead>Interval</TableHead>
              <TableHead>Status</TableHead>
              <TableHead className="text-right">Actions</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {plans.map((plan) => (
              <TableRow key={plan.id}>
                <TableCell className="font-medium">{plan.name}</TableCell>
                <TableCell>{plan.currency} {plan.price}</TableCell>
                <TableCell>{plan.billing_interval}</TableCell>
                <TableCell>
                  <span className={`inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-medium ${plan.is_active ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-800'}`}>
                    {plan.is_active ? 'Active' : 'Inactive'}
                  </span>
                </TableCell>
                <TableCell className="text-right">
                  <Button variant="ghost" size="sm" onClick={() => handleEdit(plan)}>
                    <Pencil className="h-4 w-4" />
                  </Button>
                  <Button variant="ghost" size="sm" onClick={() => handleDelete(plan.id)} className="text-red-600">
                    <Trash2 className="h-4 w-4" />
                  </Button>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>

        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>{selectedPlan ? 'Edit Plan' : 'Create New Plan'}</DialogTitle>
            </DialogHeader>
            <PlanForm 
              plan={selectedPlan} 
              onSubmit={async (data) => {
                if (selectedPlan) {
                  await updatePlan(selectedPlan.id, data);
                } else {
                  await createPlan(data as unknown);
                }
                setIsDialogOpen(false);
              }}
              isLoading={isLoading}
            />
          </DialogContent>
        </Dialog>
      </CardContent>
    </Card>
  );
}

function PlanForm({ plan, onSubmit, isLoading }: { plan: SubscriptionPlan | null, onSubmit: (data: unknown) => void, isLoading: boolean }) {
  const [formData, setFormData] = useState({
    name: plan?.name || "",
    price: plan?.price || 0,
    currency: plan?.currency || "USD",
    billing_interval: plan?.billing_interval || "monthly",
    features: plan?.features?.join('\n') || "",
    is_active: plan?.is_active ?? true
  });

  return (
    <div className="space-y-4 py-4">
      <div className="space-y-2">
        <Label>Plan Name</Label>
        <Input 
          value={formData.name} 
          onChange={e => setFormData({...formData, name: e.target.value})} 
          placeholder="e.g. Premium"
        />
      </div>
      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <Label>Price</Label>
          <Input 
            type="number"
            step="0.01"
            value={formData.price} 
            onChange={e => setFormData({...formData, price: parseFloat(e.target.value)})} 
          />
        </div>
        <div className="space-y-2">
          <Label>Currency</Label>
          <Select 
            value={formData.currency} 
            onValueChange={v => setFormData({...formData, currency: v})}
          >
            <SelectTrigger><SelectValue /></SelectTrigger>
            <SelectContent>
              <SelectItem value="USD">USD ($)</SelectItem>
              <SelectItem value="EUR">EUR (€)</SelectItem>
              <SelectItem value="GBP">GBP (£)</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>
      <div className="space-y-2">
        <Label>Billing Interval</Label>
        <Select 
          value={formData.billing_interval} 
          onValueChange={v => setFormData({...formData, billing_interval: v as unknown})}
        >
          <SelectTrigger><SelectValue /></SelectTrigger>
          <SelectContent>
            <SelectItem value="monthly">Monthly</SelectItem>
            <SelectItem value="yearly">Yearly</SelectItem>
            <SelectItem value="quarterly">Quarterly</SelectItem>
            <SelectItem value="one_time">One Time</SelectItem>
          </SelectContent>
        </Select>
      </div>
      <div className="space-y-2">
        <Label>Features (one per line)</Label>
        <textarea 
          className="flex min-h-[80px] w-full rounded-md border border-input bg-transparent px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
          value={formData.features} 
          onChange={e => setFormData({...formData, features: e.target.value})} 
          placeholder="Feature 1&#10;Feature 2&#10;Feature 3"
        />
      </div>
      <div className="flex items-center justify-between rounded-lg border p-4">
        <div className="space-y-0.5">
          <Label className="text-base">Active Status</Label>
          <p className="text-sm text-muted-foreground">
            Visible to users for purchase.
          </p>
        </div>
        <Switch 
          checked={formData.is_active}
          onCheckedChange={c => setFormData({...formData, is_active: c})}
        />
      </div>
      <Button 
        className="w-full mt-4" 
        onClick={() => onSubmit({
          ...formData,
          features: formData.features.split('\n').filter(f => f.trim())
        })} 
        disabled={isLoading}
      >
        {isLoading ? "Saving..." : "Save Plan"}
      </Button>
    </div>
  );
}

