  Upload,
  Filter,
  CheckCircle2,
  CircleDashed,
  Calendar as CalendarIcon,
  Briefcase,
  Mail,
  Phone,
  Tag,
  MapPin,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import {
  DropdownMenu,
  DropdownMenuCheckboxItem,
  DropdownMenuContent,
  DropdownMenuItem,
