  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";

export type Lead = {
  id: number;
  first_name: string;
  last_name: string;
  email: string;
  company: string | null;
  status: "new" | "contacted" | "qualified" | "lost";
  source: string | null;
  assigned_to: number | null;
  assignedUser?: {
    id: number;
    first_name: string;
    last_name: string;
  };
  created_at: string;
};

const statusColors: Record<string, string> = {
  new: "text-blue-500 bg-blue-50 dark:bg-blue-950/20",
  contacted: "text-orange-500 bg-orange-50 dark:bg-orange-950/20",
  qualified: "text-emerald-500 bg-emerald-50 dark:bg-emerald-950/20",
  lost: "text-gray-500 bg-gray-50 dark:bg-gray-950/20",
};

const defaultFormData: Partial<Lead> = {
  first_name: "",
  last_name: "",
  email: "",
  company: "",
  status: "new",
  source: "",
  assigned_to: null,
};

export function LeadsTable() {
  const [data, setData] = React.useState<Lead[]>([]);
  const [users, _setUsers] = React.useState<User[]>([]);
  const [loading, setLoading] = React.useState(true);
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [columnFilters, setColumnFilters] = React.useState<ColumnFiltersState>([]);
  const [columnVisibility, setColumnVisibility] = React.useState<VisibilityState>({});
  const [rowSelection, setRowSelection] = React.useState({});
  const { toast } = useToast();

  // Dialog States
  const [isDialogOpen, setIsDialogOpen] = React.useState(false);
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = React.useState(false);
  const [editingId, setEditingId] = React.useState<number | null>(null);
  const [deleteId, setDeleteId] = React.useState<number | null>(null);
  const [formData, setFormData] = React.useState<Partial<Lead>>(defaultFormData);

  const fetchLeads = React.useCallback(async () => {
    setLoading(true);
    try {
      const response = await marketingService.getLeads();
      const leads = response.data?.data || response.data || [];
      setData(Array.isArray(leads) ? leads : []);
    } catch (error) {
      console.error("Failed to fetch leads:", error);
      toast({
        title: "Error",
        description: "Failed to fetch leads. Please try again.",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  }, [toast]);

  React.useEffect(() => {
    fetchLeads();
  }, [fetchLeads]);

  const handleOpenCreate = () => {
    setEditingId(null);
    setFormData(defaultFormData);
    setIsDialogOpen(true);
  };

  const handleOpenEdit = (lead: Lead) => {
    setEditingId(lead.id);
    setFormData({
      first_name: lead.first_name,
      last_name: lead.last_name,
      email: lead.email,
      company: lead.company || "",
      status: lead.status,
      source: lead.source || "",
    });
    setIsDialogOpen(true);
  };

  const handleOpenDelete = (id: number) => {
    setDeleteId(id);
    setIsDeleteDialogOpen(true);
  };

  const handleSubmit = async () => {
    try {
      if (editingId) {
        await marketingService.updateLead(editingId, formData);
        toast({ title: "Success", description: "Lead updated successfully." });
      } else {
        await marketingService.createLead(formData);
        toast({ title: "Success", description: "Lead created successfully." });
      }
      setIsDialogOpen(false);
      fetchLeads();
    } catch (error) {
      console.error("Failed to save lead:", error);
      toast({
        title: "Error",
        description: "Failed to save lead. Please try again.",
        variant: "destructive",
      });
    }
  };

  const handleDelete = async () => {
    if (!deleteId) return;
    try {
      await marketingService.deleteLead(deleteId);
      toast({ title: "Success", description: "Lead deleted successfully." });
      setIsDeleteDialogOpen(false);
      fetchLeads();
    } catch (error) {
      console.error("Failed to delete lead:", error);
      toast({
        title: "Error",
        description: "Failed to delete lead. Please try again.",
        variant: "destructive",
      });
    }
  };

  const handleExport = () => {
    const csvContent = "data:text/csv;charset=utf-8," 
      + "ID,First Name,Last Name,Email,Company,Status,Source\n"
      + table.getFilteredRowModel().rows.map(row => 
        `"${row.original.id}","${row.original.first_name}","${row.original.last_name}","${row.original.email}","${row.original.company || ''}","${row.original.status}","${row.original.source || ''}"`
      ).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "leads.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const columns: ColumnDef<Lead>[] = [
    {
      accessorKey: "name",
      header: ({ column }) => {
        return (
          <Button
            variant="ghost"
            onClick={() => column.toggleSorting(column.getIsSorted() === "asc")}
          >
            Name
            <ArrowUpDown className="ml-2 h-4 w-4" />
          </Button>
        );
      },
      cell: ({ row }) => (
        <div className="flex flex-col">
          <span className="font-medium">{row.original.first_name} {row.original.last_name}</span>
          <span className="text-xs text-muted-foreground">{row.original.email}</span>
        </div>
      ),
    },
    {
      accessorKey: "company",
      header: "Company",
      cell: ({ row }) => <div>{row.getValue("company") || "-"}</div>,
    },
    {
      accessorKey: "source",
      header: "Source",
      cell: ({ row }) => <div>{row.getValue("source") || "-"}</div>,
    },
    {
      accessorKey: "status",
      header: "Status",
      cell: ({ row }) => {
        const status = row.getValue("status") as string;
        return (
          <span
            className={cn(
              "px-2.5 py-0.5 rounded-full text-xs font-medium",
              statusColors[status] || "text-gray-500 bg-gray-50"
            )}
          >
            {status.charAt(0).toUpperCase() + status.slice(1)}
          </span>
        );
      },
    },
    {
      accessorKey: "assignedUser",
      header: "Assigned To",
      cell: ({ row }) => {
        const user = row.original.assignedUser;
        return <div>{user ? `${user.first_name} ${user.last_name}` : "-"}</div>;
      },
    },
    {
      id: "actions",
      enableHiding: false,
      cell: ({ row }) => {
        const lead = row.original;

        return (
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="ghost" className="h-8 w-8 p-0">
                <span className="sr-only">Open menu</span>
                <MoreHorizontal className="h-4 w-4" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              <DropdownMenuLabel>Actions</DropdownMenuLabel>
              <DropdownMenuItem
                onClick={() => navigator.clipboard.writeText(lead.id.toString())}
              >
                Copy Lead ID
              </DropdownMenuItem>
              <DropdownMenuSeparator />
              <DropdownMenuItem onClick={() => handleOpenEdit(lead)}>
                <Pencil className="mr-2 h-4 w-4" />
                Edit Lead
              </DropdownMenuItem>
              <DropdownMenuItem 
                onClick={() => handleOpenDelete(lead.id)}
                className="text-red-600 focus:text-red-600"
              >
                <Trash2 className="mr-2 h-4 w-4" />
                Delete Lead
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        );
      },
    },
  ];

  const table = useReactTable({
    data,
    columns,
    onSortingChange: setSorting,
    onColumnFiltersChange: setColumnFilters,
    getCoreRowModel: getCoreRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    onColumnVisibilityChange: setColumnVisibility,
    onRowSelectionChange: setRowSelection,
    state: {
      sorting,
      columnFilters,
      columnVisibility,
      rowSelection,
    },
  });

  return (
    <div className="w-full space-y-4">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
            <Input
            placeholder="Filter leads..."
            value={(table.getColumn("name")?.getFilterValue() as string) ?? ""}
            onChange={(event) =>
                table.getColumn("name")?.setFilterValue(event.target.value)
            }
            className="max-w-sm"
            />
            <DropdownMenu>
                <DropdownMenuTrigger asChild>
                    <Button variant="outline" className="ml-auto">
                        <Filter className="mr-2 h-4 w-4" />
                        Status
                    </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end">
                    <DropdownMenuItem onClick={() => table.getColumn("status")?.setFilterValue(undefined)}>
                        All
                    </DropdownMenuItem>
