export interface FeatureFormData {
  title: string;
  description: string;
  status: string;
  priority: string;
  quarter: string;
  target_date: string;
}

interface FeatureFormProps {
  initialData?: FeatureFormData | null;
  onSubmit: (data: FeatureFormData) => void;
  isLoading?: boolean;
}

export function FeatureForm({ initialData, onSubmit, isLoading }: FeatureFormProps) {
  const [formData, setFormData] = useState<FeatureFormData>({
    title: "",
    description: "",
    status: "backlog",
    priority: "medium",
    quarter: "",
    target_date: ""
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        title: initialData.title || "",
        description: initialData.description || "",
        status: initialData.status || "backlog",
        priority: initialData.priority || "medium",
        quarter: initialData.quarter || "",
        target_date: initialData.target_date ? initialData.target_date.split('T')[0] : ""
      });
    }
  }, [initialData]);

  return (
    <div className="space-y-4 py-4">
      <div className="space-y-2">
        <Label>Title</Label>
        <Input 
          value={formData.title} 
          onChange={e => setFormData({...formData, title: e.target.value})} 
          placeholder="Feature title"
        />
      </div>
      <div className="space-y-2">
        <Label>Description</Label>
        <Textarea 
          value={formData.description} 
          onChange={e => setFormData({...formData, description: e.target.value})} 
          placeholder="Feature description"
        />
      </div>
      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <Label>Status</Label>
          <Select 
            value={formData.status} 
            onValueChange={v => setFormData({...formData, status: v})}
          >
            <SelectTrigger><SelectValue /></SelectTrigger>
            <SelectContent>
              <SelectItem value="backlog">Backlog</SelectItem>
              <SelectItem value="planned">Planned</SelectItem>
              <SelectItem value="in_progress">In Progress</SelectItem>
              <SelectItem value="in_qa">In QA</SelectItem>
              <SelectItem value="completed">Completed</SelectItem>
              <SelectItem value="released">Released</SelectItem>
            </SelectContent>
          </Select>
        </div>
        <div className="space-y-2">
          <Label>Priority</Label>
          <Select 
            value={formData.priority} 
            onValueChange={v => setFormData({...formData, priority: v})}
          >
            <SelectTrigger><SelectValue /></SelectTrigger>
            <SelectContent>
              <SelectItem value="low">Low</SelectItem>
              <SelectItem value="medium">Medium</SelectItem>
              <SelectItem value="high">High</SelectItem>
              <SelectItem value="critical">Critical</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>
      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <Label>Quarter</Label>
          <Input 
            value={formData.quarter} 
            onChange={e => setFormData({...formData, quarter: e.target.value})} 
            placeholder="e.g. Q1 2025"
          />
        </div>
        <div className="space-y-2">
          <Label>Target Date</Label>
          <Input 
            type="date"
            value={formData.target_date} 
            onChange={e => setFormData({...formData, target_date: e.target.value})} 
          />
        </div>
      </div>
      <Button className="w-full mt-4" onClick={() => onSubmit(formData)} disabled={isLoading}>
        {isLoading ? "Saving..." : "Save Feature"}
      </Button>
    </div>
  );
}

