const mockLeads: Lead[] = [
  { id: 1, name: "Alice Johnson", email: "alice@techcorp.com", phone: "+1234567890", company: "TechCorp", source: "Website", status: "New", value: 5000, created_at: "2023-10-01" },
  { id: 2, name: "Bob Smith", email: "bob@innovate.io", phone: "+1987654321", company: "Innovate IO", source: "Referral", status: "Contacted", value: 12000, created_at: "2023-10-02" },
  { id: 3, name: "Charlie Brown", email: "charlie@logistics.net", phone: "+1122334455", company: "Logistics Net", source: "LinkedIn", status: "Qualified", value: 8500, created_at: "2023-10-03" },
  { id: 4, name: "David Lee", email: "david@marketing.org", phone: "+1555666777", company: "Marketing Org", source: "Website", status: "Lost", value: 2000, created_at: "2023-10-04" },
  { id: 5, name: "Eve Wilson", email: "eve@retail.com", phone: "+1999888777", company: "Retail Com", source: "Cold Call", status: "Converted", value: 15000, created_at: "2023-10-05" },
];

const statusColors: Record<string, string> = {
  New: "bg-blue-100 text-blue-800",
  Contacted: "bg-yellow-100 text-yellow-800",
  Qualified: "bg-purple-100 text-purple-800",
  Lost: "bg-red-100 text-red-800",
  Converted: "bg-green-100 text-green-800",
};

export function LeadsTable() {
  const [leads, _setLeads] = React.useState<Lead[]>(mockLeads);
  const [searchQuery, setSearchQuery] = React.useState("");
  const [statusFilter, setStatusFilter] = React.useState<string>("all");
  const [sortConfig, setSortConfig] = React.useState<{ key: keyof Lead; direction: "asc" | "desc" } | null>(null);
  const [currentPage, setCurrentPage] = React.useState(1);
  const pageSize = 5;

  const filteredLeads = React.useMemo(() => {
    const filtered = leads.filter((lead) => {
      const matchesSearch =
        lead.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        lead.email.toLowerCase().includes(searchQuery.toLowerCase()) ||
        lead.company.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesStatus = statusFilter === "all" || lead.status === statusFilter;
      return matchesSearch && matchesStatus;
    });

    if (sortConfig) {
      filtered.sort((a, b) => {
        if (a[sortConfig.key] < b[sortConfig.key]) return sortConfig.direction === "asc" ? -1 : 1;
        if (a[sortConfig.key] > b[sortConfig.key]) return sortConfig.direction === "asc" ? 1 : -1;
        return 0;
      });
    }

    return filtered;
  }, [leads, searchQuery, statusFilter, sortConfig]);

  const totalPages = Math.ceil(filteredLeads.length / pageSize);
  const paginatedLeads = filteredLeads.slice((currentPage - 1) * pageSize, currentPage * pageSize);

  const handleSort = (key: keyof Lead) => {
    setSortConfig((current) => ({
      key,
      direction: current?.key === key && current.direction === "asc" ? "desc" : "asc",
    }));
  };

  const handleExport = () => {
    const csvContent = "data:text/csv;charset=utf-8,"
      + "Name,Email,Phone,Company,Source,Status,Value,Created At\n"
      + filteredLeads.map(l => `"${l.name}","${l.email}","${l.phone}","${l.company}","${l.source}","${l.status}",${l.value},${l.created_at}`).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "leads.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-col sm:flex-row gap-4 justify-between items-center">
        <div className="flex items-center gap-2 w-full sm:w-auto">
          <div className="relative flex-1 sm:w-[300px]">
            <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Search leads..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-8"
            />
          </div>
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="outline" size="icon">
                <Filter className="h-4 w-4" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              <DropdownMenuLabel>Filter by Status</DropdownMenuLabel>
              <DropdownMenuSeparator />
