                )}
                <XAxis
                  dataKey="month"
                  axisLine={false}
                  tickLine={false}
                  tick={{ fill: axisColor, fontSize: 10 }}
                  dy={8}
                />
                <YAxis
                  axisLine={false}
                  tickLine={false}
                  tick={{ fill: axisColor, fontSize: 10 }}
                  dx={-5}
                  tickFormatter={(value) => `$${(value / 1000).toFixed(0)}k`}
                  width={40}
                />
                <Tooltip
                  content={<CustomTooltip />}
                  cursor={{ stroke: isDark ? "#52525b" : "#d4d4d8" }}
                />
                {showThisYear && (
                  <Area
                    type={smoothCurve ? "monotone" : "linear"}
                    dataKey="thisYear"
                    stroke="#6e3ff3"
                    strokeWidth={2}
                    fill="url(#thisYearAreaGradient)"
                  />
                )}
                {showPrevYear && (
                  <Area
                    type={smoothCurve ? "monotone" : "linear"}
                    dataKey="prevYear"
                    stroke="#e255f2"
                    strokeWidth={2}
                    fill="url(#prevYearAreaGradient)"
                  />
                )}
              </AreaChart>
            )}
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
}

