export interface Appointment {
  id: number;
  title: string;
  patient_name: string;
  doctor_name: string;
  type: string;
  status: 'scheduled' | 'completed' | 'cancelled' | 'no_show';
  start_time: string;
  end_time: string;
  notes?: string;
}

export function AppointmentsTable() {
  const [data, setData] = React.useState<Appointment[]>([]);
  const [_isLoading, setIsLoading] = React.useState(true);
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [columnFilters, setColumnFilters] = React.useState<ColumnFiltersState>([]);
  const [columnVisibility, setColumnVisibility] = React.useState<VisibilityState>({});
  const [rowSelection, setRowSelection] = React.useState({});
  const [globalFilter, setGlobalFilter] = React.useState("");

  // Dialog states
  const [isCreateOpen, setIsCreateOpen] = React.useState(false);
  const [isEditOpen, setIsEditOpen] = React.useState(false);
  const [isDeleteOpen, setIsDeleteOpen] = React.useState(false);
  const [selectedAppointment, setSelectedAppointment] = React.useState<Appointment | null>(null);

  // Form states
  const [formData, setFormData] = React.useState({
    title: "",
    patient_name: "",
    doctor_name: "",
    type: "Consultation",
    status: "scheduled",
    start_time: "",
    end_time: "",
    notes: ""
  });

  const fetchAppointments = React.useCallback(async () => {
    try {
      setIsLoading(true);
      const result = await secretaryService.getAppointments({ search: globalFilter });
      // Ensure result is array, if paginated check data property
      setData(Array.isArray(result) ? result : result.data || []);
    } catch (error) {
      console.error("Failed to fetch appointments", error);
      toast({
        title: "Error",
        description: "Failed to load appointments.",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  }, [globalFilter]);

  React.useEffect(() => {
    fetchAppointments();
  }, [fetchAppointments]);

  const handleCreate = async () => {
    try {
      await secretaryService.createAppointment(formData);
      setIsCreateOpen(false);
      resetForm();
      fetchAppointments();
      toast({ title: "Success", description: "Appointment scheduled successfully." });
    } catch (_error) {
      toast({ title: "Error", description: "Failed to schedule appointment.", variant: "destructive" });
    }
  };

  const handleUpdate = async () => {
    if (!selectedAppointment) return;
    try {
      await secretaryService.updateAppointment(selectedAppointment.id, formData);
      setIsEditOpen(false);
      setSelectedAppointment(null);
      resetForm();
      fetchAppointments();
      toast({ title: "Success", description: "Appointment updated successfully." });
    } catch (_error) {
      toast({ title: "Error", description: "Failed to update appointment.", variant: "destructive" });
    }
  };

  const handleDelete = async () => {
    if (!selectedAppointment) return;
    try {
      await secretaryService.deleteAppointment(selectedAppointment.id);
      setIsDeleteOpen(false);
      setSelectedAppointment(null);
      fetchAppointments();
      toast({ title: "Success", description: "Appointment cancelled/deleted successfully." });
    } catch (_error) {
      toast({ title: "Error", description: "Failed to delete appointment.", variant: "destructive" });
    }
  };

  const resetForm = () => {
    setFormData({
      title: "",
      patient_name: "",
      doctor_name: "",
      type: "Consultation",
      status: "scheduled",
      start_time: "",
      end_time: "",
      notes: ""
    });
