export interface Visitor {
  id: number;
  name: string;
  email: string;
  phone: string;
  purpose: string;
  host: string;
  check_in_time: string;
  check_out_time: string | null;
  status: "checked_in" | "checked_out";
  created_at: string;
}

const _initialData: Visitor[] = [];

export function VisitorsTable() {
  const [data, setData] = React.useState<Visitor[]>([]);
  const [_isLoading, setIsLoading] = React.useState(true);
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [columnFilters, setColumnFilters] = React.useState<ColumnFiltersState>([]);
  const [columnVisibility, setColumnVisibility] = React.useState<VisibilityState>({});
  const [rowSelection, setRowSelection] = React.useState({});
  const [globalFilter, setGlobalFilter] = React.useState("");
  const [statusFilter, setStatusFilter] = React.useState<string>("all");
  const [timeFilter, setTimeFilter] = React.useState<string>("today");

  // Fetch visitors
  const fetchVisitors = React.useCallback(async () => {
    try {
      setIsLoading(true);
      const queryParams: Record<string, string> = {};
      if (globalFilter) queryParams.search = globalFilter;
      if (statusFilter !== "all") queryParams.status = statusFilter;

      if (timeFilter === 'all_time') {
        queryParams.all_time = 'true';
      } else if (timeFilter === 'last_7_days') {
        const end = new Date();
        const start = new Date();
        start.setDate(start.getDate() - 7);
        queryParams.date_from = start.toISOString().split('T')[0];
        queryParams.date_to = end.toISOString().split('T')[0];
      } else if (timeFilter === 'last_30_days') {
        const end = new Date();
        const start = new Date();
        start.setDate(start.getDate() - 30);
        queryParams.date_from = start.toISOString().split('T')[0];
        queryParams.date_to = end.toISOString().split('T')[0];
      }

      const response = await secretaryService.getVisitors(queryParams);
      if (response.success) {
        setData(response.data.data || response.data); 
      }
    } catch (error) {
      console.error("Failed to fetch visitors", error);
    } finally {
      setIsLoading(false);
    }
  }, [globalFilter, statusFilter, timeFilter]);

  React.useEffect(() => {
    const timeoutId = setTimeout(() => {
      fetchVisitors();
    }, 500); // Debounce search

    return () => clearTimeout(timeoutId);
  }, [fetchVisitors]);

  // New Visitor Dialog State
  const [isDialogOpen, setIsDialogOpen] = React.useState(false);
  const [newVisitor, setNewVisitor] = React.useState({
    name: "",
    email: "",
    phone: "",
    purpose: "",
    host: "",
  });

  const handleCheckIn = async () => {
    try {
      const response = await secretaryService.checkInVisitor(newVisitor);

      if (response.success) {
        await fetchVisitors(); // Refresh list
        setIsDialogOpen(false);
        setNewVisitor({ name: "", email: "", phone: "", purpose: "", host: "" });
        toast({ title: "Visitor Checked In", description: `${newVisitor.name} has been checked in.` });
      } else {
        toast({ title: "Error", description: "Failed to check in visitor.", variant: "destructive" });
      }
    } catch (_error) {
      toast({ title: "Error", description: "Network error occurred.", variant: "destructive" });
    }
  };

  const handleCheckOut = async (id: number) => {
    try {
      const response = await secretaryService.checkOutVisitor(id);

      if (response.success) {
        await fetchVisitors(); // Refresh list
        toast({ title: "Visitor Checked Out", description: "Check-out time recorded." });
      } else {
         toast({ title: "Error", description: "Failed to check out visitor.", variant: "destructive" });
      }
    } catch (_error) {
      toast({ title: "Error", description: "Network error occurred.", variant: "destructive" });
    }
  };

  const filteredData = React.useMemo(() => {
    let result = data;

    if (statusFilter !== "all") {
      result = result.filter((item) => item.status === statusFilter);
    }

    if (globalFilter) {
      const search = globalFilter.toLowerCase();
      result = result.filter(
        (item) =>
          item.name.toLowerCase().includes(search) ||
          item.host.toLowerCase().includes(search) ||
          item.purpose.toLowerCase().includes(search)
      );
    }

    return result;
  }, [data, globalFilter, statusFilter]);

  const columns: ColumnDef<Visitor>[] = [
    {
      id: "select",
      header: ({ table }) => (
        <Checkbox
          checked={table.getIsAllPageRowsSelected() || (table.getIsSomePageRowsSelected() && "indeterminate")}
          onCheckedChange={(value) => table.toggleAllPageRowsSelected(!!value)}
          aria-label="Select all"
        />
      ),
      cell: ({ row }) => (
        <Checkbox
          checked={row.getIsSelected()}
          onCheckedChange={(value) => row.toggleSelected(!!value)}
          aria-label="Select row"
        />
      ),
      enableSorting: false,
      enableHiding: false,
    },
    {
      accessorKey: "name",
      header: ({ column }) => {
        return (
          <Button
            variant="ghost"
            onClick={() => column.toggleSorting(column.getIsSorted() === "asc")}
          >
            Visitor
            <ArrowUpDown className="ml-2 h-4 w-4" />
          </Button>
        );
      },
      cell: ({ row }) => (
        <div className="flex flex-col">
          <span className="font-medium">{row.getValue("name")}</span>
          <span className="text-xs text-muted-foreground">{row.original.email}</span>
        </div>
      ),
    },
    {
      accessorKey: "purpose",
      header: "Purpose",
      cell: ({ row }) => <div className="font-medium">{row.getValue("purpose")}</div>,
    },
    {
      accessorKey: "host",
      header: "Host",
      cell: ({ row }) => <div className="font-medium">{row.getValue("host")}</div>,
    },
    {
      accessorKey: "check_in_time",
      header: ({ column }) => {
        return (
          <Button
            variant="ghost"
            onClick={() => column.toggleSorting(column.getIsSorted() === "asc")}
          >
            Check In
            <ArrowUpDown className="ml-2 h-4 w-4" />
          </Button>
        );
      },
      cell: ({ row }) => (
        <div className="flex items-center text-sm text-muted-foreground">
          <Clock className="mr-1 h-3 w-3" />
          {new Date(row.getValue("check_in_time")).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
        </div>
      ),
    },
    {
      accessorKey: "check_out_time",
      header: "Check Out",
      cell: ({ row }) => {
        const time = row.getValue("check_out_time") as string | null;
        return time ? (
          <div className="flex items-center text-sm text-muted-foreground">
            <Clock className="mr-1 h-3 w-3" />
            {new Date(time).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
          </div>
        ) : (
          <span className="text-muted-foreground text-sm">-</span>
        );
      },
    },
    {
      accessorKey: "status",
      header: "Status",
      cell: ({ row }) => {
        const status = row.getValue("status") as string;
        return (
          <Badge variant={status === 'checked_in' ? "default" : "secondary"}>
            {status === 'checked_in' ? "On Premise" : "Left"}
          </Badge>
        );
      },
    },
    {
      id: "actions",
      cell: ({ row }) => {
        const visitor = row.original;
        return (
          <div className="flex items-center justify-end gap-2">
            {visitor.status === 'checked_in' && (
              <Button variant="ghost" size="sm" onClick={() => handleCheckOut(visitor.id)}>
                <LogOut className="mr-2 h-4 w-4" />
                Check Out
              </Button>
            )}
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="ghost" className="h-8 w-8 p-0">
                  <span className="sr-only">Open menu</span>
                  <MoreHorizontal className="h-4 w-4" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end">
                <DropdownMenuLabel>Actions</DropdownMenuLabel>
                <DropdownMenuItem onClick={() => navigator.clipboard.writeText(visitor.email)}>
                  Copy Email
                </DropdownMenuItem>
                <DropdownMenuSeparator />
                <DropdownMenuItem>View Details</DropdownMenuItem>
                <DropdownMenuItem>Edit Record</DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        );
      },
    },
  ];

  const table = useReactTable({
    data: filteredData,
    columns,
    onSortingChange: setSorting,
    onColumnFiltersChange: setColumnFilters,
    getCoreRowModel: getCoreRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    onColumnVisibilityChange: setColumnVisibility,
    onRowSelectionChange: setRowSelection,
    state: {
      sorting,
      columnFilters,
      columnVisibility,
      rowSelection,
    },
  });

  const handleExport = () => {
    const csvContent = "data:text/csv;charset=utf-8,"
      + "Name,Email,Phone,Purpose,Host,Check In,Check Out,Status\n"
      + table.getFilteredRowModel().rows.map(row => 
        `"${row.original.name}","${row.original.email}","${row.original.phone}","${row.original.purpose}","${row.original.host}","${row.original.check_in_time}","${row.original.check_out_time || ''}","${row.original.status}"`
      ).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "visitors_log.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="w-full space-y-4">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 py-4">
        <div className="flex items-center gap-2 w-full sm:w-auto">
          <div className="relative w-full sm:w-64">
            <Search className="absolute left-2 top-2.5 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Search visitors..."
              value={globalFilter}
              onChange={(event) => setGlobalFilter(event.target.value)}
              className="pl-8"
            />
          </div>
          <Select value={timeFilter} onValueChange={setTimeFilter}>
            <SelectTrigger className="w-[150px]">
              <SelectValue placeholder="Period" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="today">Today</SelectItem>
              <SelectItem value="last_7_days">Last 7 Days</SelectItem>
              <SelectItem value="last_30_days">Last 30 Days</SelectItem>
              <SelectItem value="all_time">All Time</SelectItem>
            </SelectContent>
          </Select>
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="outline" size="icon">
                <Filter className="h-4 w-4" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              <DropdownMenuLabel>Filter by Status</DropdownMenuLabel>
              <DropdownMenuItem onClick={() => setStatusFilter("all")}>
                All
              </DropdownMenuItem>
              <DropdownMenuItem onClick={() => setStatusFilter("checked_in")}>
                On Premise
              </DropdownMenuItem>
              <DropdownMenuItem onClick={() => setStatusFilter("checked_out")}>
                Checked Out
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
        <div className="flex items-center gap-2 w-full sm:w-auto justify-end">
          <Button variant="outline" onClick={handleExport}>
            <Download className="mr-2 h-4 w-4" /> Export Log
          </Button>
          <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
            <DialogTrigger asChild>
              <Button>
                <Plus className="mr-2 h-4 w-4" /> New Visitor
              </Button>
            </DialogTrigger>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>Visitor Check-In</DialogTitle>
                <DialogDescription>
                  Enter visitor details for check-in.
                </DialogDescription>
              </DialogHeader>
              <div className="grid gap-4 py-4">
                <div className="grid grid-cols-4 items-center gap-4">
                  <Label htmlFor="name" className="text-right">Name</Label>
