              </DropdownMenuTrigger>
              <DropdownMenuContent align="end">
                 <DropdownMenuLabel>Filter by Level</DropdownMenuLabel>
                 <DropdownMenuItem onClick={() => table.getColumn("level")?.setFilterValue("")}>
                   All Levels
