"use client";

import { useEffect, useState, useMemo } from "react";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuCheckboxItem,
  DropdownMenuSeparator,
  DropdownMenuLabel,
} from "@/components/ui/dropdown-menu";
import {
  Users,
  Search,
  Filter,
  Download,
  Upload,
  MoreHorizontal,
  ChevronUp,
  ChevronDown,
  Plus,
  Trash,
  Edit,
} from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { useTherapistStore, type Patient } from "@/store/therapist-store";
import { cn } from "@/lib/utils";
import { format } from "date-fns";
import { PatientForm } from "./patient-form";
import { therapistService } from "@/lib/api/therapist";
import { toast } from "@/components/ui/use-toast";

const _PAGE_SIZE_OPTIONS = [8, 15, 25, 50];

const statusColors: Record<string, { bg: string; text: string; border: string }> = {
  active: {
    bg: "bg-emerald-50 dark:bg-emerald-950/30",
    text: "text-emerald-600 dark:text-emerald-400",
    border: "border-emerald-200 dark:border-emerald-800",
  },
  inactive: {
    bg: "bg-slate-50 dark:bg-slate-950/30",
    text: "text-slate-600 dark:text-slate-400",
    border: "border-slate-200 dark:border-slate-800",
  },
  monitoring: {
    bg: "bg-blue-50 dark:bg-blue-950/30",
    text: "text-blue-600 dark:text-blue-400",
    border: "border-blue-200 dark:border-blue-800",
  },
  critical: {
    bg: "bg-red-50 dark:bg-red-950/30",
    text: "text-red-600 dark:text-red-400",
    border: "border-red-200 dark:border-red-800",
  },
};

export function PatientsTable() {
  const patients = useTherapistStore((state) => state.patients);
  const fetchPatients = useTherapistStore((state) => state.fetchPatients);
  const searchQuery = useTherapistStore((state) => state.searchQuery);
  const departmentFilter = useTherapistStore((state) => state.departmentFilter);
  const statusFilter = useTherapistStore((state) => state.statusFilter);
  const setSearchQuery = useTherapistStore((state) => state.setSearchQuery);
  const setDepartmentFilter = useTherapistStore((state) => state.setDepartmentFilter);
  const setStatusFilter = useTherapistStore((state) => state.setStatusFilter);

  const [sortConfig, setSortConfig] = useState<{ key: keyof Patient; direction: 'asc' | 'desc' } | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);

  useEffect(() => {
    fetchPatients();
  }, [fetchPatients]);

  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, _setPageSize] = useState(8);

  const hasActiveFilters = departmentFilter !== "all" || statusFilter !== "all";

  const handleSort = (key: keyof Patient) => {
    setSortConfig((current) => {
      if (current?.key === key) {
        return current.direction === 'asc' 
          ? { key, direction: 'desc' } 
          : null;
      }
      return { key, direction: 'asc' };
    });
  };

  const filteredPatients = useMemo(() => {
    const result = patients.filter((patient) => {
      const fullName = `${patient.first_name} ${patient.last_name}`;
      const matchesSearch =
        fullName.toLowerCase().includes(searchQuery.toLowerCase()) ||
        patient.email.toLowerCase().includes(searchQuery.toLowerCase()) ||
        patient.uuid.toLowerCase().includes(searchQuery.toLowerCase());

      const matchesDepartment =
        departmentFilter === "all" || patient.department === departmentFilter;

      const matchesStatus =
        statusFilter === "all" || patient.status === statusFilter;

      return matchesSearch && matchesDepartment && matchesStatus;
    });

    if (sortConfig) {
      result.sort((a, b) => {
        const aValue = a[sortConfig.key];
        const bValue = b[sortConfig.key];

        if (aValue === undefined || bValue === undefined) return 0;

        if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
        if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
      });
    }

    return result;
  }, [patients, searchQuery, departmentFilter, statusFilter, sortConfig]);

  const _totalPages = Math.ceil(filteredPatients.length / pageSize);

  const paginatedPatients = useMemo(() => {
    const startIndex = (currentPage - 1) * pageSize;
    return filteredPatients.slice(startIndex, startIndex + pageSize);
  }, [filteredPatients, currentPage, pageSize]);

  useEffect(() => {
    setCurrentPage(1);
  }, [searchQuery, departmentFilter, statusFilter, pageSize]);

  const handleExport = () => {
    const headers = ["ID", "Name", "Email", "Department", "Status", "Joined"];
    const csvContent = [
      headers.join(","),
      ...filteredPatients.map(p => [
        p.uuid,
        `"${p.first_name} ${p.last_name}"`,
        p.email,
        p.department || "N/A",
        p.status || "active",
        format(new Date(p.created_at), 'yyyy-MM-dd')
      ].join(","))
    ].join("\n");

    const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", "patients_export.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    toast({ title: "Exported", description: "Patients list exported to CSV" });
  };

  const handleImport = () => {
    const input = document.createElement("input");
    input.type = "file";
    input.accept = ".csv";
    input.onchange = async (e: unknown) => {
      const file = e.target.files[0];
      if (file) {
        try {
          await therapistService.importPatients(file);
          toast({ title: "Success", description: "Patients imported successfully" });
          fetchPatients();
        } catch (_error) {
          toast({ title: "Error", description: "Import failed", variant: "destructive" });
        }
      }
    };
    input.click();
  };

  const handleCreate = () => {
    setSelectedPatient(null);
    setIsModalOpen(true);
  };

  const handleEdit = (patient: Patient) => {
    setSelectedPatient(patient);
    setIsModalOpen(true);
  };

  const handleDelete = async (patient: Patient) => {
    if (confirm(`Are you sure you want to delete ${patient.first_name} ${patient.last_name}?`)) {
      try {
        await therapistService.deletePatient(patient.id);
        toast({ title: "Success", description: "Patient deleted successfully" });
        fetchPatients();
      } catch (_error) {
        toast({ title: "Error", description: "Delete failed", variant: "destructive" });
      }
    }
  };

  const handleFormSubmit = async (data: unknown) => {
    try {
      if (selectedPatient) {
        await therapistService.updatePatient(selectedPatient.id, data);
        toast({ title: "Success", description: "Patient updated successfully" });
      } else {
        await therapistService.createPatient(data);
        toast({ title: "Success", description: "Patient created successfully" });
      }
      fetchPatients();
    } catch (error) {
      console.error(error);
      toast({ title: "Error", description: "Operation failed", variant: "destructive" });
    }
  };

  return (
    <>
      <div className="rounded-xl border bg-card overflow-hidden">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 px-5 py-4 border-b">
          <div className="flex items-center gap-2">
            <Users className="size-5 text-muted-foreground" />
            <span className="font-medium text-muted-foreground">
              Patient list
            </span>
            <Badge variant="secondary" className="ml-2">
              {filteredPatients.length}
            </Badge>
          </div>

          <div className="flex flex-wrap items-center gap-2">
            <div className="relative flex-1 sm:flex-none">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-muted-foreground" />
              <Input
                placeholder="Search patients..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-9 w-full sm:w-[220px] h-9"
              />
            </div>

            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="outline" size="sm" className="h-9 gap-2">
                  <Filter className="size-4" />
                  Filter
                  {hasActiveFilters && (
                    <span className="size-1.5 rounded-full bg-primary" />
                  )}
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end" className="w-[200px]">
                <DropdownMenuLabel>Department</DropdownMenuLabel>
                {["all", "General", "Mental Health", "Physical Therapy", "Nutrition", "Cardiology"].map(
                  (dept) => (
                    <DropdownMenuCheckboxItem
                      key={dept}
                      checked={departmentFilter === dept}
                      onCheckedChange={() => setDepartmentFilter(dept)}
                    >
                      {dept === "all" ? "All Departments" : dept}
                    </DropdownMenuCheckboxItem>
                  )
                )}
                <DropdownMenuSeparator />
                <DropdownMenuLabel>Status</DropdownMenuLabel>
                {["all", "Active", "Discharged", "Monitoring", "Critical"].map(
                  (status) => (
                    <DropdownMenuCheckboxItem
                      key={status}
                      checked={statusFilter === status}
                      onCheckedChange={() => setStatusFilter(status)}
                    >
                      {status === "all" ? "All Statuses" : status}
                    </DropdownMenuCheckboxItem>
                  )
                )}
              </DropdownMenuContent>
            </DropdownMenu>

            <Button variant="outline" size="sm" className="h-9 gap-2" onClick={handleExport}>
              <Download className="size-4" />
              Export
            </Button>
            <Button variant="outline" size="sm" className="h-9 gap-2" onClick={handleImport}>
